using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestHelper
    {
        public static SchoolContext CreateContext(string? dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            return new SchoolContext(options);
        }

        public static void DrainNotificationQueue()
        {
            using var service = new NotificationService();
            while (service.ReceiveNotification() != null) { }
        }

        public static void SeedStudents(SchoolContext context)
        {
            context.Students.AddRange(
                new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2020-09-01") },
                new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2021-09-01") },
                new Student { FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2022-09-01") }
            );
            context.SaveChanges();
        }

        public static void SeedInstructors(SchoolContext context)
        {
            context.Instructors.AddRange(
                new Instructor
                {
                    FirstMidName = "Kim",
                    LastName = "Abercrombie",
                    HireDate = DateTime.Parse("1995-03-11"),
                    CourseAssignments = new List<CourseAssignment>()
                },
                new Instructor
                {
                    FirstMidName = "Fadi",
                    LastName = "Fakhouri",
                    HireDate = DateTime.Parse("2002-07-06"),
                    CourseAssignments = new List<CourseAssignment>()
                }
            );
            context.SaveChanges();
        }

        public static void SeedDepartments(SchoolContext context)
        {
            // Ensure instructors exist first
            if (!context.Instructors.Any())
                SeedInstructors(context);

            var instructor = context.Instructors.First();
            context.Departments.AddRange(
                new Department { Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = instructor.ID },
                new Department { Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01") }
            );
            context.SaveChanges();
        }

        public static void SeedCourses(SchoolContext context)
        {
            if (!context.Departments.Any())
                SeedDepartments(context);

            var dept = context.Departments.First();
            context.Courses.AddRange(
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = dept.DepartmentID }
            );
            context.SaveChanges();
        }

        public static void SeedFullData(SchoolContext context)
        {
            SeedStudents(context);
            SeedInstructors(context);
            SeedDepartments(context);
            SeedCourses(context);

            // Add enrollments
            var student = context.Students.First();
            var course = context.Courses.First();
            context.Enrollments.Add(new Enrollment
            {
                StudentID = student.ID,
                CourseID = course.CourseID,
                Grade = Grade.A
            });
            context.SaveChanges();

            // Add course assignments
            var instructor = context.Instructors.First();
            context.CourseAssignments.Add(new CourseAssignment
            {
                InstructorID = instructor.ID,
                CourseID = course.CourseID
            });
            context.SaveChanges();
        }
    }
}

using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_SetsPageIndexAndTotalPages()
        {
            // Arrange & Act
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 2, 3);

            // Assert
            Assert.AreEqual(2, list.PageIndex);
            Assert.AreEqual(4, list.TotalPages); // ceil(10/3) = 4
            Assert.AreEqual(3, list.Count);
        }

        [TestMethod]
        public void Constructor_AddsAllItems()
        {
            var items = new List<string> { "a", "b", "c" };
            var list = new PaginatedList<string>(items, 3, 1, 3);

            CollectionAssert.AreEqual(items, list);
        }

        [TestMethod]
        [DataRow(1, false, DisplayName = "Page 1 has no previous")]
        [DataRow(2, true, DisplayName = "Page 2 has previous")]
        [DataRow(3, true, DisplayName = "Page 3 has previous")]
        public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
        {
            var list = new PaginatedList<int>(new List<int>(), 30, pageIndex, 10);
            Assert.AreEqual(expected, list.HasPreviousPage);
        }

        [TestMethod]
        [DataRow(1, 3, true, DisplayName = "Page 1 of 3 has next")]
        [DataRow(3, 3, false, DisplayName = "Last page has no next")]
        [DataRow(2, 3, true, DisplayName = "Middle page has next")]
        [DataRow(1, 1, false, DisplayName = "Single page has no next")]
        public void HasNextPage_ReturnsCorrectValue(int pageIndex, int totalPages, bool expected)
        {
            int count = totalPages * 5;
            var list = new PaginatedList<int>(new List<int>(), count, pageIndex, 5);
            Assert.AreEqual(expected, list.HasNextPage);
        }

        [TestMethod]
        public void Create_PaginatesCorrectly()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var page1 = PaginatedList<int>.Create(source, 1, 10);
            var page2 = PaginatedList<int>.Create(source, 2, 10);
            var page3 = PaginatedList<int>.Create(source, 3, 10);

            Assert.AreEqual(10, page1.Count);
            Assert.AreEqual(10, page2.Count);
            Assert.AreEqual(5, page3.Count);
            Assert.AreEqual(3, page1.TotalPages);
            Assert.AreEqual(1, page1[0]);
            Assert.AreEqual(11, page2[0]);
            Assert.AreEqual(21, page3[0]);
        }

        [TestMethod]
        public void Create_SinglePage_NoNextOrPrevious()
        {
            var source = Enumerable.Range(1, 5).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(1, result.TotalPages);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }

        [TestMethod]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.AreEqual(0, result.Count);
            Assert.AreEqual(0, result.TotalPages);
        }

        [TestMethod]
        public void TotalPages_CeilsCorrectly()
        {
            // 7 items, page size 3 => ceil(7/3) = 3
            var list = new PaginatedList<int>(new List<int>(), 7, 1, 3);
            Assert.AreEqual(3, list.TotalPages);
        }
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Models
{
    [TestClass]
    public sealed class ModelTests
    {
        [TestMethod]
        public void Person_FullName_ReturnsLastNameCommaFirstName()
        {
            var student = new Student { LastName = "Smith", FirstMidName = "John" };
            Assert.AreEqual("Smith, John", student.FullName);
        }

        [TestMethod]
        public void ErrorViewModel_ShowRequestId_TrueWhenSet()
        {
            var model = new ErrorViewModel { RequestId = "abc123" };
            Assert.IsTrue(model.ShowRequestId);
        }

        [TestMethod]
        [DataRow(null, DisplayName = "Null RequestId")]
        [DataRow("", DisplayName = "Empty RequestId")]
        public void ErrorViewModel_ShowRequestId_FalseWhenNullOrEmpty(string? requestId)
        {
            var model = new ErrorViewModel { RequestId = requestId! };
            Assert.IsFalse(model.ShowRequestId);
        }

        [TestMethod]
        public void Student_Properties_SetCorrectly()
        {
            var date = new DateTime(2023, 9, 1);
            var student = new Student
            {
                ID = 1,
                LastName = "Doe",
                FirstMidName = "Jane",
                EnrollmentDate = date,
                Enrollments = new List<Enrollment>()
            };

            Assert.AreEqual(1, student.ID);
            Assert.AreEqual("Doe", student.LastName);
            Assert.AreEqual("Jane", student.FirstMidName);
            Assert.AreEqual(date, student.EnrollmentDate);
            Assert.AreEqual(0, student.Enrollments.Count);
        }

        [TestMethod]
        public void Instructor_Properties_SetCorrectly()
        {
            var date = new DateTime(2000, 1, 15);
            var instructor = new Instructor
            {
                ID = 1,
                LastName = "Smith",
                FirstMidName = "Bob",
                HireDate = date,
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { Location = "Room 101" }
            };

            Assert.AreEqual(date, instructor.HireDate);
            Assert.AreEqual("Room 101", instructor.OfficeAssignment.Location);
            Assert.AreEqual(0, instructor.CourseAssignments.Count);
        }

        [TestMethod]
        public void Course_Properties_SetCorrectly()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/images/chem.jpg"
            };

            Assert.AreEqual(1050, course.CourseID);
            Assert.AreEqual("Chemistry", course.Title);
            Assert.AreEqual(3, course.Credits);
            Assert.AreEqual(1, course.DepartmentID);
            Assert.AreEqual("/images/chem.jpg", course.TeachingMaterialImagePath);
        }

        [TestMethod]
        public void Department_Properties_SetCorrectly()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = 5
            };

            Assert.AreEqual(1, dept.DepartmentID);
            Assert.AreEqual("Engineering", dept.Name);
            Assert.AreEqual(350000m, dept.Budget);
            Assert.AreEqual(5, dept.InstructorID);
        }

        [TestMethod]
        public void Enrollment_GradeCanBeNull()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 100,
                StudentID = 200,
                Grade = null
            };

            Assert.IsNull(enrollment.Grade);
        }

        [TestMethod]
        [DataRow(Grade.A, DisplayName = "Grade A")]
        [DataRow(Grade.B, DisplayName = "Grade B")]
        [DataRow(Grade.C, DisplayName = "Grade C")]
        [DataRow(Grade.D, DisplayName = "Grade D")]
        [DataRow(Grade.F, DisplayName = "Grade F")]
        public void Enrollment_AllGradeValues(Grade grade)
        {
            var enrollment = new Enrollment { Grade = grade };
            Assert.AreEqual(grade, enrollment.Grade);
        }

        [TestMethod]
        public void Notification_Properties_SetCorrectly()
        {
            var now = DateTime.Now;
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "New student created",
                CreatedAt = now,
                CreatedBy = "Admin",
                IsRead = false,
                ReadAt = null
            };

            Assert.AreEqual(1, notification.Id);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("42", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("New student created", notification.Message);
            Assert.AreEqual(now, notification.CreatedAt);
            Assert.AreEqual("Admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
            Assert.IsNull(notification.ReadAt);
        }

        [TestMethod]
        public void EntityOperation_HasExpectedValues()
        {
            Assert.AreEqual(0, (int)EntityOperation.CREATE);
            Assert.AreEqual(1, (int)EntityOperation.UPDATE);
            Assert.AreEqual(2, (int)EntityOperation.DELETE);
        }

        [TestMethod]
        public void CourseAssignment_Properties_SetCorrectly()
        {
            var assignment = new CourseAssignment { InstructorID = 1, CourseID = 100 };
            Assert.AreEqual(1, assignment.InstructorID);
            Assert.AreEqual(100, assignment.CourseID);
        }

        [TestMethod]
        public void OfficeAssignment_Properties_SetCorrectly()
        {
            var office = new OfficeAssignment { InstructorID = 5, Location = "Thompson 304" };
            Assert.AreEqual(5, office.InstructorID);
            Assert.AreEqual("Thompson 304", office.Location);
        }

        [TestMethod]
        public void EnrollmentDateGroup_Properties_SetCorrectly()
        {
            var group = new EnrollmentDateGroup
            {
                EnrollmentDate = new DateTime(2020, 9, 1),
                StudentCount = 15
            };

            Assert.AreEqual(new DateTime(2020, 9, 1), group.EnrollmentDate);
            Assert.AreEqual(15, group.StudentCount);
        }

        [TestMethod]
        public void AssignedCourseData_Properties_SetCorrectly()
        {
            var data = new AssignedCourseData
            {
                CourseID = 100,
                Title = "Chemistry",
                Assigned = true
            };

