+                new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2021-09-01") },
+                new Student { FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2022-09-01") }
+            );
+            context.SaveChanges();
+        }
+
+        public static void SeedInstructors(SchoolContext context)
+        {
+            context.Instructors.AddRange(
+                new Instructor
+                {
+                    FirstMidName = "Kim",
+                    LastName = "Abercrombie",
+                    HireDate = DateTime.Parse("1995-03-11"),
+                    CourseAssignments = new List<CourseAssignment>()
+                },
+                new Instructor
+                {
+                    FirstMidName = "Fadi",
+                    LastName = "Fakhouri",
+                    HireDate = DateTime.Parse("2002-07-06"),
+                    CourseAssignments = new List<CourseAssignment>()
+                }
+            );
+            context.SaveChanges();
+        }
+
+        public static void SeedDepartments(SchoolContext context)
+        {
+            // Ensure instructors exist first
+            if (!context.Instructors.Any())
+                SeedInstructors(context);
+
+            var instructor = context.Instructors.First();
+            context.Departments.AddRange(
+                new Department { Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = instructor.ID },
+                new Department { Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01") }
+            );
+            context.SaveChanges();
+        }
+
+        public static void SeedCourses(SchoolContext context)
+        {
