using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Models
{
    [TestClass]
    public sealed class ModelTests
    {
        [TestMethod]
        public void Person_FullName_ReturnsLastNameCommaFirstName()
        {
            var student = new Student { LastName = "Smith", FirstMidName = "John" };
            Assert.AreEqual("Smith, John", student.FullName);
        }

        [TestMethod]
        public void ErrorViewModel_ShowRequestId_TrueWhenSet()
        {
            var model = new ErrorViewModel { RequestId = "abc123" };
            Assert.IsTrue(model.ShowRequestId);
        }

        [TestMethod]
        [DataRow(null, DisplayName = "Null RequestId")]
        [DataRow("", DisplayName = "Empty RequestId")]
        public void ErrorViewModel_ShowRequestId_FalseWhenNullOrEmpty(string? requestId)
        {
            var model = new ErrorViewModel { RequestId = requestId! };
            Assert.IsFalse(model.ShowRequestId);
        }

        [TestMethod]
        public void Student_Properties_SetCorrectly()
        {
            var date = new DateTime(2023, 9, 1);
            var student = new Student
            {
                ID = 1,
                LastName = "Doe",
                FirstMidName = "Jane",
                EnrollmentDate = date,
                Enrollments = new List<Enrollment>()
            };

            Assert.AreEqual(1, student.ID);
            Assert.AreEqual("Doe", student.LastName);
            Assert.AreEqual("Jane", student.FirstMidName);
            Assert.AreEqual(date, student.EnrollmentDate);
            Assert.AreEqual(0, student.Enrollments.Count);
        }

        [TestMethod]
        public void Instructor_Properties_SetCorrectly()
        {
            var date = new DateTime(2000, 1, 15);
            var instructor = new Instructor
            {
                ID = 1,
                LastName = "Smith",
                FirstMidName = "Bob",
                HireDate = date,
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { Location = "Room 101" }
            };

            Assert.AreEqual(date, instructor.HireDate);
            Assert.AreEqual("Room 101", instructor.OfficeAssignment.Location);
            Assert.AreEqual(0, instructor.CourseAssignments.Count);
        }

        [TestMethod]
        public void Course_Properties_SetCorrectly()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/images/chem.jpg"
            };

            Assert.AreEqual(1050, course.CourseID);
            Assert.AreEqual("Chemistry", course.Title);
            Assert.AreEqual(3, course.Credits);
            Assert.AreEqual(1, course.DepartmentID);
            Assert.AreEqual("/images/chem.jpg", course.TeachingMaterialImagePath);
        }

        [TestMethod]
        public void Department_Properties_SetCorrectly()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = 5
            };

            Assert.AreEqual(1, dept.DepartmentID);
            Assert.AreEqual("Engineering", dept.Name);
            Assert.AreEqual(350000m, dept.Budget);
            Assert.AreEqual(5, dept.InstructorID);
        }

        [TestMethod]
        public void Enrollment_GradeCanBeNull()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 100,
                StudentID = 200,
                Grade = null
            };

            Assert.IsNull(enrollment.Grade);
        }

        [TestMethod]
        [DataRow(Grade.A, DisplayName = "Grade A")]
        [DataRow(Grade.B, DisplayName = "Grade B")]
        [DataRow(Grade.C, DisplayName = "Grade C")]
        [DataRow(Grade.D, DisplayName = "Grade D")]
        [DataRow(Grade.F, DisplayName = "Grade F")]
        public void Enrollment_AllGradeValues(Grade grade)
        {
            var enrollment = new Enrollment { Grade = grade };
            Assert.AreEqual(grade, enrollment.Grade);
        }

        [TestMethod]
        public void Notification_Properties_SetCorrectly()
        {
            var now = DateTime.Now;
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "New student created",
                CreatedAt = now,
                CreatedBy = "Admin",
                IsRead = false,
                ReadAt = null
            };

            Assert.AreEqual(1, notification.Id);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("42", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("New student created", notification.Message);
            Assert.AreEqual(now, notification.CreatedAt);
            Assert.AreEqual("Admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
            Assert.IsNull(notification.ReadAt);
        }

        [TestMethod]
        public void EntityOperation_HasExpectedValues()
        {
            Assert.AreEqual(0, (int)EntityOperation.CREATE);
            Assert.AreEqual(1, (int)EntityOperation.UPDATE);
            Assert.AreEqual(2, (int)EntityOperation.DELETE);
        }

        [TestMethod]
        public void CourseAssignment_Properties_SetCorrectly()
        {
            var assignment = new CourseAssignment { InstructorID = 1, CourseID = 100 };
            Assert.AreEqual(1, assignment.InstructorID);
            Assert.AreEqual(100, assignment.CourseID);
        }

        [TestMethod]
        public void OfficeAssignment_Properties_SetCorrectly()
        {
            var office = new OfficeAssignment { InstructorID = 5, Location = "Thompson 304" };
            Assert.AreEqual(5, office.InstructorID);
            Assert.AreEqual("Thompson 304", office.Location);
        }

        [TestMethod]
        public void EnrollmentDateGroup_Properties_SetCorrectly()
        {
            var group = new EnrollmentDateGroup
            {
                EnrollmentDate = new DateTime(2020, 9, 1),
                StudentCount = 15
            };

            Assert.AreEqual(new DateTime(2020, 9, 1), group.EnrollmentDate);
            Assert.AreEqual(15, group.StudentCount);
        }

        [TestMethod]
        public void AssignedCourseData_Properties_SetCorrectly()
        {
            var data = new AssignedCourseData
            {
                CourseID = 100,
                Title = "Chemistry",
                Assigned = true
            };

            Assert.AreEqual(100, data.CourseID);
            Assert.AreEqual("Chemistry", data.Title);
            Assert.IsTrue(data.Assigned);
        }

        [TestMethod]
        public void InstructorIndexData_Properties_SetCorrectly()
        {
            var viewModel = new InstructorIndexData
            {
                Instructors = new List<Instructor>(),
                Courses = new List<Course>(),
                Enrollments = new List<Enrollment>()
            };

            Assert.IsNotNull(viewModel.Instructors);
            Assert.IsNotNull(viewModel.Courses);
            Assert.IsNotNull(viewModel.Enrollments);
        }
    }
}

