using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut = null!;

        [TestInitialize]
        public void Setup()
        {
            TestHelper.DrainNotificationQueue();
            _sut = new NotificationService();
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut.Dispose();
            TestHelper.DrainNotificationQueue();
        }

        [TestMethod]
        public void SendNotification_EnqueuesNotification()
        {
            _sut.SendNotification("Student", "1", EntityOperation.CREATE, "Admin");

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("Admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_IncludesNameInMessage()
        {
            _sut.SendNotification("Course", "100", "Chemistry", EntityOperation.CREATE, "Admin");

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains("Chemistry"));
            Assert.IsTrue(notification.Message.Contains("created"));
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _sut.SendNotification("Course", "100", EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains("ID: 100"));
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "created", DisplayName = "CREATE message")]
        [DataRow(EntityOperation.UPDATE, "updated", DisplayName = "UPDATE message")]
        [DataRow(EntityOperation.DELETE, "deleted", DisplayName = "DELETE message")]
        public void SendNotification_GeneratesCorrectMessage(EntityOperation operation, string expectedVerb)
        {
            _sut.SendNotification("Student", "1", "John Doe", operation);

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains(expectedVerb),
                $"Expected message to contain '{expectedVerb}', got: {notification.Message}");
        }

        [TestMethod]
        public void SendNotification_DefaultUserName_IsSystem()
        {
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var result = _sut.ReceiveNotification();
            Assert.IsNull(result);
        }

        [TestMethod]
        public void ReceiveNotification_FIFO_Order()
        {
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);
            _sut.SendNotification("Course", "2", EntityOperation.UPDATE);
            _sut.SendNotification("Department", "3", EntityOperation.DELETE);

            var first = _sut.ReceiveNotification();
            var second = _sut.ReceiveNotification();
            var third = _sut.ReceiveNotification();

            Assert.AreEqual("Student", first!.EntityType);
            Assert.AreEqual("Course", second!.EntityType);
            Assert.AreEqual("Department", third!.EntityType);
        }

        [TestMethod]
        public void ReceiveNotification_RemovesFromQueue()
        {
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);

            var first = _sut.ReceiveNotification();
            var second = _sut.ReceiveNotification();

            Assert.IsNotNull(first);
            Assert.IsNull(second);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for the in-memory implementation
            _sut.MarkAsRead(1);
            _sut.MarkAsRead(999);
        }

        [TestMethod]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            service.Dispose();
            // Should not throw even after dispose
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now;

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after);
        }

        [TestMethod]
        public void SendNotification_SetsOperationString()
        {
            _sut.SendNotification("Student", "1", EntityOperation.UPDATE);

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("UPDATE", notification.Operation);
        }
    }
}

