using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class NotificationsControllerTests
    {
        private SchoolContext _context = null!;
        private NotificationsController _controller = null!;

        [TestInitialize]
        public void Setup()
        {
            TestHelper.DrainNotificationQueue();
            _context = TestHelper.CreateContext();
            _controller = new NotificationsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller.Dispose();
            _context.Dispose();
            TestHelper.DrainNotificationQueue();
        }

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();

            Assert.IsInstanceOfType<ViewResult>(result);
        }

        [TestMethod]
        public void GetNotifications_EmptyQueue_ReturnsEmptyList()
        {
            var result = _controller.GetNotifications();

            Assert.IsNotNull(result);
            var jsonResult = result as JsonResult;
            Assert.IsNotNull(jsonResult);
        }

        [TestMethod]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Enqueue some notifications via the service
            using var service = new NotificationService();
            service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);
            service.SendNotification("Course", "100", "Chemistry", EntityOperation.UPDATE);

            var result = _controller.GetNotifications() as JsonResult;

            Assert.IsNotNull(result);
            // The result contains an anonymous type with success, notifications, count
            Assert.IsNotNull(result.Value);
        }

        [TestMethod]
        public void GetNotifications_LimitsTo10()
        {
            using var service = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                service.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
            }

            var result = _controller.GetNotifications() as JsonResult;

            Assert.IsNotNull(result);
            // The controller limits to 10 notifications per call
            Assert.IsNotNull(result.Value);
        }

        [TestMethod]
        public void MarkAsRead_ReturnsSuccess()
        {
            var result = _controller.MarkAsRead(1) as JsonResult;

            Assert.IsNotNull(result);
            Assert.IsNotNull(result.Value);
        }
    }
}

