using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using System;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class StudentsControllerTests
    {
        private SchoolContext _context = null!;
        private StudentsController _controller = null!;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelper.CreateContext();
            _controller = new StudentsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [TestMethod]
        public void Index_ReturnsViewWithPaginatedStudents()
        {
            TestHelper.SeedStudents(_context);

            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(3, model.Count);
        }

        [TestMethod]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            TestHelper.SeedStudents(_context);

            var result = _controller.Index(null, null, null, null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;

            Assert.AreEqual("Alexander", model![0].LastName);
            Assert.AreEqual("Alonso", model[1].LastName);
            Assert.AreEqual("Anand", model[2].LastName);
        }

        [TestMethod]
        public void Index_NameDesc_OrdersByLastNameDescending()
        {
            TestHelper.SeedStudents(_context);

            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;

            Assert.AreEqual("Anand", model![0].LastName);
            Assert.AreEqual("Alonso", model[1].LastName);
            Assert.AreEqual("Alexander", model[2].LastName);
        }

        [TestMethod]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            TestHelper.SeedStudents(_context);

            var result = _controller.Index("Date", null, null, null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;

            Assert.IsTrue(model![0].EnrollmentDate <= model[1].EnrollmentDate);
            Assert.IsTrue(model[1].EnrollmentDate <= model[2].EnrollmentDate);
        }

        [TestMethod]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            TestHelper.SeedStudents(_context);

            var result = _controller.Index("date_desc", null, null, null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;

            Assert.IsTrue(model![0].EnrollmentDate >= model[1].EnrollmentDate);
            Assert.IsTrue(model[1].EnrollmentDate >= model[2].EnrollmentDate);
        }

        [TestMethod]
        public void Index_SearchByLastName_FiltersResults()
        {
            TestHelper.SeedStudents(_context);

            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;

            Assert.AreEqual(1, model!.Count);
            Assert.AreEqual("Alexander", model[0].LastName);
        }

        [TestMethod]
        public void Index_SearchByFirstName_FiltersResults()
        {
            TestHelper.SeedStudents(_context);

            var result = _controller.Index(null, null, "Carson", null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;

            Assert.AreEqual(1, model!.Count);
            Assert.AreEqual("Carson", model[0].FirstMidName);
        }

        [TestMethod]
        public void Index_SearchNoMatch_ReturnsEmpty()
        {
            TestHelper.SeedStudents(_context);

            var result = _controller.Index(null, null, "NonExistent", null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;

            Assert.AreEqual(0, model!.Count);
        }

        [TestMethod]
        public void Index_NewSearch_ResetsToPage1()
        {
            TestHelper.SeedStudents(_context);

            var result = _controller.Index(null, null, "A", null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;

            Assert.AreEqual(1, model!.PageIndex);
        }

        [TestMethod]
        public void Index_CurrentFilter_MaintainedWhenNoNewSearch()
        {
            TestHelper.SeedStudents(_context);

            _controller.Index(null, "Alexander", null, 1);

            Assert.AreEqual("Alexander", _controller.ViewBag.CurrentFilter);
        }

        [TestMethod]
        public void Index_SetsViewBagSortParameters()
        {
            TestHelper.SeedStudents(_context);

            _controller.Index(null, null, null, null);

            Assert.AreEqual("name_desc", _controller.ViewBag.NameSortParm);
            Assert.AreEqual("Date", _controller.ViewBag.DateSortParm);
        }

        #endregion

        #region Details

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = result as StatusCodeResult;
            Assert.IsNotNull(statusResult);
            Assert.AreEqual(400, statusResult.StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            TestHelper.SeedStudents(_context);
            var student = _context.Students.First();

            var result = _controller.Details(student.ID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(student.ID, model.ID);
        }

        #endregion

        #region Create

        [TestMethod]
        public void Create_GET_ReturnsViewWithStudent()
        {
            var result = _controller.Create() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
        }

        [TestMethod]
        public void Create_POST_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student);

            var redirect = result as RedirectToActionResult;
            Assert.IsNotNull(redirect);
            Assert.AreEqual("Index", redirect.ActionName);
            Assert.AreEqual(1, _context.Students.Count());
        }

        [TestMethod]
        public void Create_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreEqual(0, _context.Students.Count());
        }

        [TestMethod]
        public void Create_POST_DefaultDate_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [TestMethod]
        public void Create_POST_DateBeforeSqlMinimum_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(1752, 1, 1)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        #endregion

        #region Edit

        [TestMethod]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);

            var statusResult = result as StatusCodeResult;
            Assert.IsNotNull(statusResult);
            Assert.AreEqual(400, statusResult.StatusCode);
        }

        [TestMethod]
        public void Edit_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999);

            Assert.IsInstanceOfType<NotFoundResult>(result);
        }

        [TestMethod]
        public void Edit_GET_ValidId_ReturnsViewWithStudent()
        {
            TestHelper.SeedStudents(_context);
            var student = _context.Students.First();

            var result = _controller.Edit(student.ID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.AreEqual(student.ID, model!.ID);
        }

        [TestMethod]
        public void Edit_POST_ValidStudent_RedirectsToIndex()
        {
            TestHelper.SeedStudents(_context);
            var student = _context.Students.First();

            // Detach the tracked entity so the edit POST can attach its own
            _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updatedStudent = new Student
            {
                ID = student.ID,
                LastName = "Updated",
                FirstMidName = student.FirstMidName,
                EnrollmentDate = student.EnrollmentDate
            };

            var result = _controller.Edit(updatedStudent);

            var redirect = result as RedirectToActionResult;
            Assert.IsNotNull(redirect);
            Assert.AreEqual("Index", redirect.ActionName);
        }

        [TestMethod]
        public void Edit_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                ID = 1,
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Edit_POST_DefaultDate_AddsModelError()
        {
            var student = new Student
            {
                ID = 1,
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        #endregion

        #region Delete

        [TestMethod]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = result as StatusCodeResult;
            Assert.IsNotNull(statusResult);
            Assert.AreEqual(400, statusResult.StatusCode);
        }

        [TestMethod]
        public void Delete_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsInstanceOfType<NotFoundResult>(result);
        }

        [TestMethod]
        public void Delete_GET_ValidId_ReturnsView()
        {
            TestHelper.SeedStudents(_context);
            var student = _context.Students.First();

            var result = _controller.Delete(student.ID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.AreEqual(student.ID, model!.ID);
        }

        [TestMethod]
        public void DeleteConfirmed_ValidId_RemovesAndRedirects()
        {
            TestHelper.SeedStudents(_context);
            var student = _context.Students.First();
            var initialCount = _context.Students.Count();

            var result = _controller.DeleteConfirmed(student.ID);

            var redirect = result as RedirectToActionResult;
            Assert.IsNotNull(redirect);
            Assert.AreEqual("Index", redirect.ActionName);
            Assert.AreEqual(initialCount - 1, _context.Students.Count());
        }

        [TestMethod]
        public void DeleteConfirmed_InvalidId_RedirectsWithError()
        {
            // The controller wraps in try-catch and redirects to Index
            var result = _controller.DeleteConfirmed(999);

            var redirect = result as RedirectToActionResult;
            Assert.IsNotNull(redirect);
            Assert.AreEqual("Index", redirect.ActionName);
        }

        #endregion
    }
