using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class DepartmentsControllerTests
    {
        private SchoolContext _context = null!;
        private DepartmentsController _controller = null!;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelper.CreateContext();
            _controller = new DepartmentsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [TestMethod]
        public void Index_ReturnsViewWithDepartments()
        {
            TestHelper.SeedDepartments(_context);

            var result = _controller.Index() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<Department>;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Count);
        }

        [TestMethod]
        public void Index_EmptyDatabase_ReturnsEmptyList()
        {
            var result = _controller.Index() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<Department>;
            Assert.IsNotNull(model);
            Assert.AreEqual(0, model.Count);
        }

        #endregion

        #region Details

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = result as StatusCodeResult;
            Assert.IsNotNull(statusResult);
            Assert.AreEqual(400, statusResult.StatusCode);
        }

        [TestMethod]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsInstanceOfType<NotFoundResult>(result);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            TestHelper.SeedDepartments(_context);
            var dept = _context.Departments.First();

            var result = _controller.Details(dept.DepartmentID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Department;
            Assert.AreEqual(dept.DepartmentID, model!.DepartmentID);
        }

        #endregion

        #region Create

        [TestMethod]
        public void Create_GET_ReturnsView()
        {
            TestHelper.SeedInstructors(_context);

            var result = _controller.Create() as ViewResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Create_POST_ValidDepartment_RedirectsToIndex()
        {
            TestHelper.SeedInstructors(_context);
            var instructor = _context.Instructors.First();
            var dept = new Department
            {
                Name = "Science",
                Budget = 250000,
                StartDate = new DateTime(2023, 9, 1),
                InstructorID = instructor.ID
            };

            var result = _controller.Create(dept);

            var redirect = result as RedirectToActionResult;
            Assert.IsNotNull(redirect);
            Assert.AreEqual("Index", redirect.ActionName);
            Assert.AreEqual(1, _context.Departments.Count());
        }

        [TestMethod]
        public void Create_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department();

            var result = _controller.Create(dept) as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreEqual(0, _context.Departments.Count());
        }

        #endregion

        #region Edit

        [TestMethod]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);

            var statusResult = result as StatusCodeResult;
            Assert.IsNotNull(statusResult);
            Assert.AreEqual(400, statusResult.StatusCode);
        }

        [TestMethod]
        public void Edit_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999);

            Assert.IsInstanceOfType<NotFoundResult>(result);
        }

        [TestMethod]
        public void Edit_GET_ValidId_ReturnsView()
        {
            TestHelper.SeedDepartments(_context);
            var dept = _context.Departments.First();

            var result = _controller.Edit(dept.DepartmentID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Department;
            Assert.AreEqual(dept.DepartmentID, model!.DepartmentID);
        }

        [TestMethod]
        public void Edit_POST_ValidDepartment_RedirectsToIndex()
        {
            TestHelper.SeedDepartments(_context);
            var dept = _context.Departments.First();
            _context.Entry(dept).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updatedDept = new Department
            {
                DepartmentID = dept.DepartmentID,
                Name = "Updated",
                Budget = 500000,
                StartDate = dept.StartDate,
                InstructorID = dept.InstructorID
            };

            var result = _controller.Edit(updatedDept);

            var redirect = result as RedirectToActionResult;
            Assert.IsNotNull(redirect);
            Assert.AreEqual("Index", redirect.ActionName);
        }

        [TestMethod]
        public void Edit_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department { DepartmentID = 1 };

            var result = _controller.Edit(dept) as ViewResult;

            Assert.IsNotNull(result);
        }

        #endregion

        #region Delete

        [TestMethod]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = result as StatusCodeResult;
            Assert.IsNotNull(statusResult);
            Assert.AreEqual(400, statusResult.StatusCode);
        }

        [TestMethod]
        public void Delete_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsInstanceOfType<NotFoundResult>(result);
        }

        [TestMethod]
        public void Delete_GET_ValidId_ReturnsView()
        {
            TestHelper.SeedDepartments(_context);
            var dept = _context.Departments.First();

            var result = _controller.Delete(dept.DepartmentID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Department;
            Assert.AreEqual(dept.DepartmentID, model!.DepartmentID);
        }

        [TestMethod]
        public void DeleteConfirmed_RemovesDepartmentAndRedirects()
        {
            TestHelper.SeedDepartments(_context);
            var dept = _context.Departments.First();
            var initialCount = _context.Departments.Count();

            var result = _controller.DeleteConfirmed(dept.DepartmentID);

            var redirect = result as RedirectToActionResult;
            Assert.IsNotNull(redirect);
            Assert.AreEqual("Index", redirect.ActionName);
            Assert.AreEqual(initialCount - 1, _context.Departments.Count());
        }

        #endregion
    }
}

