using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class InstructorsControllerTests
    {
        private SchoolContext _context = null!;
        private InstructorsController _controller = null!;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelper.CreateContext();
            _controller = new InstructorsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [TestMethod]
        public void Index_ReturnsViewWithInstructorData()
        {
            SeedInstructorsWithCourses();

            var result = _controller.Index(null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.IsTrue(model.Instructors.Any());
        }

        [TestMethod]
        public void Index_OrdersByLastName()
        {
            SeedInstructorsWithCourses();

            var result = _controller.Index(null, null) as ViewResult;
            var model = result!.Model as InstructorIndexData;
            var instructors = model!.Instructors.ToList();

            for (int i = 1; i < instructors.Count; i++)
            {
                Assert.IsTrue(
                    string.Compare(instructors[i - 1].LastName, instructors[i].LastName, StringComparison.Ordinal) <= 0);
            }
        }

        [TestMethod]
        public void Index_WithInstructorId_SetsCourses()
        {
            SeedInstructorsWithCourses();
            var instructor = _context.Instructors
                .Include(i => i.CourseAssignments)
                .First(i => i.CourseAssignments.Any());

            var result = _controller.Index(instructor.ID, null) as ViewResult;
            var model = result!.Model as InstructorIndexData;

            Assert.IsNotNull(model!.Courses);
            Assert.IsTrue(model.Courses.Any());
        }

        [TestMethod]
        public void Index_WithoutInstructorId_CoursesNull()
        {
            SeedInstructorsWithCourses();

            var result = _controller.Index(null, null) as ViewResult;
            var model = result!.Model as InstructorIndexData;

            Assert.IsNull(model!.Courses);
        }

        #endregion

        #region Details

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = result as StatusCodeResult;
            Assert.IsNotNull(statusResult);
            Assert.AreEqual(400, statusResult.StatusCode);
        }

        [TestMethod]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsInstanceOfType<NotFoundResult>(result);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            TestHelper.SeedInstructors(_context);
            var instructor = _context.Instructors.First();

            var result = _controller.Details(instructor.ID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.AreEqual(instructor.ID, model!.ID);
        }

        #endregion

        #region Create

        [TestMethod]
        public void Create_GET_ReturnsViewWithInstructor()
        {
            var result = _controller.Create() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.IsNotNull(model);
            Assert.IsNotNull(model.CourseAssignments);
        }

        [TestMethod]
        public void Create_POST_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2020, 1, 15),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null);

            var redirect = result as RedirectToActionResult;
            Assert.IsNotNull(redirect);
            Assert.AreEqual("Index", redirect.ActionName);
            Assert.AreEqual(1, _context.Instructors.Count());
        }

        [TestMethod]
        public void Create_POST_WithSelectedCourses_AssignsCourses()
        {
            TestHelper.SeedCourses(_context);
            var courseIds = _context.Courses.Select(c => c.CourseID.ToString()).ToArray();

            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2020, 1, 15),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, courseIds);

            var redirect = result as RedirectToActionResult;
            Assert.IsNotNull(redirect);

            var saved = _context.Instructors
                .Include(i => i.CourseAssignments)
                .First(i => i.LastName == "NewInstructor");
            Assert.AreEqual(courseIds.Length, saved.CourseAssignments.Count);
        }

        [TestMethod]
        public void Create_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                HireDate = new DateTime(2020, 1, 15),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null) as ViewResult;

            Assert.IsNotNull(result);
        }

        #endregion

        #region Edit

        [TestMethod]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);

            var statusResult = result as StatusCodeResult;
            Assert.IsNotNull(statusResult);
            Assert.AreEqual(400, statusResult.StatusCode);
        }

        [TestMethod]
        public void Edit_GET_ValidId_ReturnsView()
        {
            SeedInstructorsWithCourses();
            var instructor = _context.Instructors
                .Include(i => i.CourseAssignments)
                    .ThenInclude(c => c.Course)
                .Include(i => i.OfficeAssignment)
                .First();

            var result = _controller.Edit(instructor.ID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.AreEqual(instructor.ID, model!.ID);
        }

        #endregion

        #region Delete

        [TestMethod]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = result as StatusCodeResult;
            Assert.IsNotNull(statusResult);
            Assert.AreEqual(400, statusResult.StatusCode);
        }

        [TestMethod]
        public void Delete_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsInstanceOfType<NotFoundResult>(result);
        }

        [TestMethod]
        public void Delete_GET_ValidId_ReturnsView()
        {
            TestHelper.SeedInstructors(_context);
            var instructor = _context.Instructors.First();

            var result = _controller.Delete(instructor.ID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.AreEqual(instructor.ID, model!.ID);
        }

        [TestMethod]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            SeedInstructorsWithCourses();
            var instructor = _context.Instructors
                .Include(i => i.OfficeAssignment)
                .First();
            var initialCount = _context.Instructors.Count();

            var result = _controller.DeleteConfirmed(instructor.ID);

            var redirect = result as RedirectToActionResult;
            Assert.IsNotNull(redirect);
            Assert.AreEqual("Index", redirect.ActionName);
            Assert.AreEqual(initialCount - 1, _context.Instructors.Count());
        }

        [TestMethod]
        public void DeleteConfirmed_InstructorAsDeptAdmin_ClearsDepartmentAdmin()
        {
            SeedInstructorsWithCourses();
            var instructor = _context.Instructors
                .Include(i => i.OfficeAssignment)
                .First();

            // Make this instructor a department admin
            var dept = _context.Departments.First();
            dept.InstructorID = instructor.ID;
            _context.SaveChanges();

            _controller.DeleteConfirmed(instructor.ID);

            var updatedDept = _context.Departments.Find(dept.DepartmentID);
            Assert.IsNull(updatedDept!.InstructorID);
        }

        #endregion

        #region Helpers

        private void SeedInstructorsWithCourses()
        {
            TestHelper.SeedFullData(_context);
        }

        #endregion
    }
}

