[TestMethod]
public void DeleteConfirmed_InstructorAsDeptAdmin_ClearsDepartmentAdmin()
{
    SeedInstructorsWithCourses();

    // Use the second instructor who is NOT already a department admin
    var instructor = _context.Instructors
        .Include(i => i.OfficeAssignment)
        .OrderBy(i => i.ID)
        .Skip(1)
        .First();

    // Ensure this instructor is not admin of any existing department
    foreach (var d in _context.Departments.Where(d => d.InstructorID == instructor.ID))
    {
        d.InstructorID = null;
    }
    _context.SaveChanges();

    // Now make this instructor admin of exactly one department
    var dept = _context.Departments.First();
    dept.InstructorID = instructor.ID;
    _context.SaveChanges();

    _controller.DeleteConfirmed(instructor.ID);

    var updatedDept = _context.Departments.Find(dept.DepartmentID);
    Assert.IsNull(updatedDept!.InstructorID);
}

